#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor gemm_max_subtract_gelu_impl_npu(const at::Tensor& x,
                                           const at::Tensor& w,
                                           const at::Tensor& b,
                                           int64_t max_dim) {
    // Output shape as per fused pipeline with keepdim=True after max
    TORCH_CHECK(x.dim() == 2 && w.dim() == 2, \"x and w must be 2D\");
    TORCH_CHECK(x.size(1) == w.size(1), \"in_features mismatch between x and w\");
    TORCH_CHECK(b.dim() == 1 && b.size(0) == w.size(0), \"bias shape mismatch\");

    at::Tensor y;
    if (max_dim == 1) {
        y = at::empty({x.size(0), 1}, x.options());
    } else if (max_dim == 0) {
        y = at::empty({1, w.size(0)}, x.options());
    } else {
        TORCH_CHECK(false, \"max_dim must be 0 or 1\");
    }

    EXEC_NPU_CMD(aclnnGemmMaxSubtractGeluCustom, x, w, b, max_dim, y);
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl(\"gemm_max_subtract_gelu_custom\", &gemm_max_subtract_gelu_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def(\"gemm_max_subtract_gelu_custom\", &gemm_max_subtract_gelu_impl_npu,
          \"Fused GEMM->Max->MeanSub->GELU (GemmMaxSubtractGeluCustom on NPU)\");
}
